function normalizePercentages(arr) {
  const total = arr.reduce((sum, val) => sum + val, 0);
  if (total === 0) return arr.map(() => 0);
  return arr.map((val) => val / total * 100);
}
function weightedRandomIndex(percentages) {
  const total = percentages.reduce((sum, val) => sum + val, 0);
  const rand = Math.random() * total;
  let cumulative = 0;
  for (let i4 = 0; i4 < percentages.length; i4++) {
    cumulative += percentages[i4];
    if (rand < cumulative) return i4;
  }
  return percentages.length - 1;
}
