var Reports, reports_default;
var init_reports = __esm({
  "api/reports.js"() {
    init_prismarinedb();
    Reports = class {
      constructor() {
        this.db = prismarineDb.table("Reports");
      }
      create(name, body, type, player2) {
        if (this.db.findFirst({ name })) return false;
        this.db.insertDocument({
          name,
          body,
          type,
          player: player2.name
        });
        return true;
      }
      get(id2) {
        let r = this.db.getByID(id2);
        if (!r) return false;
        return r;
      }
      getAll() {
        return this.db.findDocuments();
      }
      delete(id2) {
        let r = this.db.getByID(id2);
        if (!r) return false;
        this.db.deleteDocumentByID(id2);
        return true;
      }
      getFromPlayer(name) {
        return this.db.findDocuments({ player: name });
      }
    };
    reports_default = new Reports();
  }
});

