// features/afk.js
import { system as system71, world as world118 } from "@minecraft/server";
function getAfkTimeout() {
  return 60;
}
var players;
var init_afk = __esm({
  "features/afk.js"() {
    init_configAPI();
    players = {};
    configAPI_default.registerProperty("AFKSystem", configAPI_default.Types.Boolean, true);
    system71.runInterval(() => {
      if (!configAPI_default.getProperty("AFKSystem")) return;
      for (const player2 of world118.getPlayers()) {
        if (!players[player2.id]) {
          players[player2.id] = {
            loc: player2.location,
            rot: player2.getRotation(),
            afkFor: 0
          };
        } else {
          let { loc, rot } = players[player2.id];
          let rotation = player2.getRotation();
          if (loc.x != player2.location.x || loc.y != player2.location.y || loc.z != player2.location.z) {
            if (players[player2.id].afkFor >= getAfkTimeout()) {
              world118.sendMessage(`\xA77* ${player2.name} is no longer AFK`);
            }
            players[player2.id].afkFor = 0;
          } else {
            players[player2.id].afkFor++;
          }
          if (players[player2.id].afkFor == getAfkTimeout()) {
            players[player2.id].preAfkLocation = {
              x: player2.location.x,
              y: player2.location.y,
              z: player2.location.z
            };
            world118.sendMessage(`\xA77* ${player2.name} is now AFK`);
          }
          players[player2.id] = {
            ...players[player2.id],
            loc: player2.location,
            rot: player2.getRotation()
          };
        }
      }
    }, 20);
  }
});

