    system74.afterEvents.scriptEventReceive.subscribe((e) => {
      if (e.id == "leaf:import_internal_uis") {
        for (const doc of uiBuilder_default.internalUIs) {
          uiBuilder_default.db.insertDocument(doc);
        }
      }
      if (e.id == "leaf:toast") {
        let args2 = betterArgs(e.message);
        args2 = args2.map((_3) => {
          if (_3 != '""') return _3;
          return "";
        });
        e.sourceEntity.sendMessage(
          dynamicToast(
            args2[0] ? args2[0] : "",
            args2[1] ? args2[1] : "",
            args2[2] ? args2[2] : ""
          )
        );
      }
      if (e.sourceEntity && e.sourceEntity.typeId == "minecraft:player") {
        if (e.id == "leaf:open_tabbed") {
          let tabUI2 = uiBuilder_default.tabbedDB.findFirst({ title: e.message });
          if (!tabUI2) return;
          openTabUI(tabUI2, e.sourceEntity);
        }
        if (e.id == "leaf:apply_impulse") {
          e.sourceEntity.applyImpulse({ x: 1, y: 1, z: 1 });
        }
        if (e.id == "leaf:transfer_server") {
          transferPlayer(
            e.sourceEntity,
            e.message.split(":")[0],
            parseInt(e.message.split(":")[1])
          );
        }
        if (e.id == "leaf:delay") {
          let amt = parseInt(e.message.split(" ")[0]);
          let cmd = e.message.split(" ").slice(1).join(" ").trim();
          system74.runTimeout(() => {
            e.sourceEntity.runCommand(
              cmd.startsWith("/") ? cmd.substring(1) : cmd
            );
          }, amt);
        }
      }
    });
